css:
.loader {color: var(--loader-color, #0284c7);
  --loader-secondary-color: #7dd3fc;
  --loader-bg: #ffffff;
  width: 80px;
  height: 70px;
  border: 5px solid currentColor;
  padding: 0 8px;
  box-sizing: border-box;
  background:linear-gradient(var(--loader-bg, #ffffff) 0 0) 0 0/8px 20px,linear-gradient(var(--loader-bg, #ffffff) 0 0) 100% 0/8px 20px,radial-gradient(farthest-side,var(--loader-bg, #ffffff) 90%,#0000) 0 5px/8px 8px content-box,currentColor;
  background-repeat: no-repeat;
  animation: l3 2s infinite linear;
}@keyframes l3{25% {background-position: 0 0 ,100% 100%,100% calc(100% - 5px)}50% {background-position: 0 100%,100% 100%,0 calc(100% - 5px)}75% {background-position: 0 100%,100% 0,100% 5px}}
